322→    abilities.results as any[],
323→    modifiers.results as any[],
324→    types.results as any[],
325→  );
326→
327→  c.header("Cache-Control", "public, max-age=300, s-maxage=3600, stale-while-revalidate=86400");
328→
329→  return c.json({ data: parsed });
330→});
