 11→export const API_URL =
 12→  import.meta.env.VITE_API_URL ??
 13→  import.meta.env.PUBLIC_API_URL ??
 14→  "";
 15→
 16→export function imageUrl(key: string | null): string | null {
 17→  if (!key) return null;
 18→  return `${API_URL}/images/${key}`;
