109→export async function fetchCards(params: {
110→  q?: string;
111→  category?: string;
112→  set?: string;
113→  limit?: number;
114→  offset?: number;
115→  rarity?: string;
116→  stage?: string;
117→  trainer_type?: string;
118→  energy_type?: string;
119→  retreat?: string;
120→  hp_min?: string;
121→  hp_max?: string;
122→  types?: string;
123→  weakness?: string;
124→  resistance?: string;
125→  legal_standard?: string;
126→  legal_expanded?: string;
127→}): Promise<CardListResponse> {
128→  const url = new URL("/api/cards", API_URL);
129→
130→  if (params.q) url.searchParams.set("q", params.q);
131→  if (params.category) url.searchParams.set("category", params.category);
132→  if (params.set) url.searchParams.set("set", params.set);
133→  if (params.limit != null) url.searchParams.set("limit", String(params.limit));
134→  if (params.offset != null) url.searchParams.set("offset", String(params.offset));
135→  if (params.rarity) url.searchParams.set("rarity", params.rarity);
136→  if (params.stage) url.searchParams.set("stage", params.stage);
137→  if (params.trainer_type) url.searchParams.set("trainer_type", params.trainer_type);
138→  if (params.energy_type) url.searchParams.set("energy_type", params.energy_type);
139→  if (params.retreat) url.searchParams.set("retreat", params.retreat);
140→  if (params.hp_min) url.searchParams.set("hp_min", params.hp_min);
141→  if (params.hp_max) url.searchParams.set("hp_max", params.hp_max);
142→  if (params.types) url.searchParams.set("types", params.types);
143→  if (params.weakness) url.searchParams.set("weakness", params.weakness);
144→  if (params.resistance) url.searchParams.set("resistance", params.resistance);
145→  if (params.legal_standard) url.searchParams.set("legal_standard", params.legal_standard);
146→  if (params.legal_expanded) url.searchParams.set("legal_expanded", params.legal_expanded);
147→
148→  const key = url.toString();
149→  const cached = cache.get(key);
150→  if (cached && performance.now() - cached.ts < CACHE_TTL) {
151→    return cached.data;
152→  }
153→
154→  const res = await fetch(key);
155→  if (!res.ok) {
156→    throw new Error(`API error: ${res.status}`);
157→  }
158→  const data = parseJson(
159→    await res.json(),
160→    isCardListResponse,
161→    "Invalid cards payload",
162→  );
163→  cache.set(key, { data, ts: performance.now() });
164→  evictOldest(cache);
165→  return data;
166→}
