228→function isDeckListResponse(
229→  value: unknown,
230→): value is { data: DeckSummary[] } {
231→  return hasDataEnvelope(value, Array.isArray);
232→}
233→
234→function isRuleStatus(value: unknown): value is { allowed: boolean; reason: string | null } {
235→  return (
236→    isRecord(value) &&
237→    typeof value.allowed === "boolean" &&
238→    (typeof value.reason === "string" || value.reason === null)
239→  );
240→}
241→
242→function isAttackRule(value: unknown): value is SimulatorRulesResponse["attacks"][number] {
243→  return (
244→    isRecord(value) &&
245→    typeof value.index === "number" &&
246→    typeof value.name === "string" &&
247→    isRuleStatus(value)
248→  );
249→}
250→
251→function isAbilityRule(value: unknown): value is SimulatorRulesResponse["abilities"][number] {
252→  return (
253→    isRecord(value) &&
254→    typeof value.pokemonUid === "string" &&
255→    typeof value.abilityIdx === "number" &&
256→    typeof value.name === "string" &&
257→    isRuleStatus(value)
258→  );
259→}
260→
261→function isRuleStatusMap(value: unknown): value is Record<string, { allowed: boolean; reason: string | null }> {
262→  return isRecord(value) && Object.values(value).every(isRuleStatus);
263→}
264→
265→function isHandCardRules(value: unknown): value is SimulatorRulesResponse["hand"][string] {
266→  return (
267→    isRecord(value) &&
268→    isRuleStatus(value.active) &&
269→    isRuleStatus(value.bench) &&
270→    isRuleStatus(value.stadium) &&
271→    isRuleStatus(value.trainerUse) &&
272→    isRuleStatusMap(value.benchPokemon)
273→  );
274→}
275→
276→function isSimulatorRulesResponse(value: unknown): value is SimulatorRulesResponse {
277→  return (
278→    isRecord(value) &&
279→    (value.currentPlayer === 0 || value.currentPlayer === 1) &&
280→    typeof value.locked === "boolean" &&
281→    isRuleStatus(value.endTurn) &&
282→    isRuleStatus(value.stadiumAbility) &&
283→    Array.isArray(value.attacks) &&
284→    value.attacks.every(isAttackRule) &&
285→    Array.isArray(value.abilities) &&
286→    value.abilities.every(isAbilityRule) &&
287→    isRuleStatusMap(value.retreatTargets) &&
288→    isRecord(value.hand) &&
289→    Object.values(value.hand).every(isHandCardRules)
290→  );
291→}
292→
293→function isUnknownValue(_value: unknown): _value is unknown {
294→  return true;
295→}
